function RiftWordmark({ width = 200 }) {
  const [err, setErr] = useState(false)
  if (err) return <div style={{ fontFamily:"'Poppins',sans-serif", fontSize: width*0.28, fontWeight: 800, letterSpacing: 8, color:'var(--pri)', lineHeight:1 }}>RIFT</div>
  return <img src={RIFT_LOGO_URL} alt="RIFT" style={{ width, display:'block', mixBlendMode:'screen' }} onError={() => setErr(true)} />
}

function RiftLogo({ size = 20 }) {
  const [err, setErr] = useState(false)
  if (err) return <span style={{ fontFamily:"'Poppins',sans-serif", fontSize: size*0.8, fontWeight: 800, color:'var(--pri)', letterSpacing:2 }}>R</span>
  return <img src={RIFT_LOGO_URL} alt="RIFT" style={{ height: size, display:'block', mixBlendMode:'screen' }} onError={() => setErr(true)} />
}



