function TokenAvatar({ token, size = 40 }) {
  const [err, setErr] = useState(false)
  const uri = token.logoURI   // only try actual image URLs
  if (uri && !err) {
    return (
      <img src={uri} alt={token.sym} onError={() => setErr(true)}
        style={{ width:size, height:size, borderRadius:'50%', objectFit:'cover', flexShrink:0, background:'#111' }} />
    )
  }
  const bg  = token.bg  || 'rgba(153,69,255,.15)'
  const clr = token.clr || '#B980FF'
  // Use the logo symbol character if available, else first 2 chars of sym
  const label = token.logo || (token.sym||'?').slice(0,2).toUpperCase()
  const isSymbol = token.logo && token.logo.length <= 2   // single char symbols render bigger
  return (
    <div style={{ width:size, height:size, borderRadius:'50%', background:bg, color:clr,
      display:'flex', alignItems:'center', justifyContent:'center',
      fontSize: isSymbol ? size*0.46 : size*0.34, fontWeight:800, flexShrink:0,
      fontFamily:"'Poppins',sans-serif", letterSpacing:-0.5 }}>
      {label}
    </div>
  )
}

