// ─── QR PLACEHOLDER ───────────────────────────────────────────────────────────
function QRPlaceholder({ size = 140 }) {
  const cells = 21
  const cellSize = size / cells
  // Generate a stable visual QR-like pattern
  const grid = []
  for (let r = 0; r < cells; r++) {
    for (let c = 0; c < cells; c++) {
      const isCorner = (r < 7 && c < 7) || (r < 7 && c >= cells-7) || (r >= cells-7 && c < 7)
      const fill = isCorner ? ((r===0||r===6||c===0||c===6) || (r>=2&&r<=4&&c>=2&&c<=4) || (r>=2&&r<=4&&c>=cells-5&&c<=cells-3) || (r>=cells-5&&r<=cells-3&&c>=2&&c<=4)) : (Math.sin(r*3.7+c*2.1)>0.2)
      if (fill) grid.push({ r, c })
    }
  }
  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} style={{ display: 'block' }}>
      <rect width={size} height={size} fill="white" />
      {grid.map(({ r, c }) => (
        <rect key={`${r}-${c}`} x={c*cellSize} y={r*cellSize} width={cellSize} height={cellSize} fill="#0a0a0a" />
      ))}
    </svg>
  )
}

