// ─── PRINTER HOOK — Epson TM-T20II via bridge ws://192.168.1.104:8766 ────────
const PRINTER_WS = 'ws://192.168.1.104:8766'

function usePrinter(onWalletGenerated) {
  const ws = useRef(null)
  const [status, setStatus] = useState('idle')
  const onWalletRef = useRef(onWalletGenerated)
  useEffect(() => { onWalletRef.current = onWalletGenerated }, [onWalletGenerated])

  const connect = useCallback(() => {
    try {
      ws.current = new WebSocket(PRINTER_WS)
      ws.current.onopen  = () => console.log('🖨️ Printer bridge connecté')
      ws.current.onclose = () => console.log('🖨️ Printer bridge déconnecté')
      ws.current.onmessage = (e) => {
        const msg = JSON.parse(e.data)
        if (msg.status === 'wallet_generated' && msg.publicKey) {
          if (onWalletRef.current) onWalletRef.current(msg.publicKey, msg.privateKey)
          setStatus('done')
        } else {
          setStatus(msg.status === 'error' ? 'error' : 'done')
        }
      }
    } catch(e) { console.warn('Printer bridge non disponible:', e.message) }
  }, [])

  const print = useCallback((data) => {
    if (!ws.current || ws.current.readyState !== WebSocket.OPEN) connect()
    setTimeout(() => {
      if (ws.current?.readyState === WebSocket.OPEN) {
        setStatus('printing')
        ws.current.send(JSON.stringify(data))
      } else {
        setStatus('error')
      }
    }, 300)
  }, [connect])

  useEffect(() => { connect() }, [connect])

  return { print, status }
}

