// ─── SCREEN: CHECK PENDING — scan ticket QR pour reprendre ───────────────────
function SellCheckScreen({ go, session, setSession }) {
  const lang    = session.lang || 'en'
  const [scanned, setScanned] = useState('')
  const [status,  setStatus]  = useState('')
  const [error,   setError]   = useState('')
  const inputRef = useRef(null)

  // Focus agressif scanner
  useEffect(() => {
    const focus = () => inputRef.current?.focus()
    focus()
    const iv = setInterval(focus, 300)
    document.addEventListener('click', focus)
    return () => { clearInterval(iv); document.removeEventListener('click', focus) }
  }, [])

  // Empêche scroll
  useEffect(() => {
    const fn = (e) => { if ([32,13,38,40].includes(e.keyCode)) e.preventDefault() }
    window.addEventListener('keydown', fn, { passive:false })
    return () => window.removeEventListener('keydown', fn)
  }, [])

  const handleScan = (val) => {
    setScanned(val)
    // Attend le Enter (fin de scan)
  }

  const processTicket = () => {
    const v = scanned.trim()
    // Parse rift://collect?ref=XXX&payout=YYY&asset=ZZZ
    if (v.startsWith('rift://collect?') || v.includes('ref=')) {
      try {
        const params = new URLSearchParams(v.includes('?') ? v.split('?')[1] : v)
        const ref    = params.get('ref')
        const payout = parseInt(params.get('payout')) || 0
        const asset  = params.get('asset') || 'SOL'
        if (ref && payout > 0) {
          // Verifie si ticket deja utilise
          const usedRefs = JSON.parse(localStorage.getItem('usedRefs') || '[]')
          if (usedRefs.includes(ref)) {
            setError(tr(lang,'ticketUsed'))
            setScanned('')
            return
          }
          setStatus(tr(lang,'validatingTx'))
          setSession(s => ({...s,
            sellRef:       ref,
            sellAsset:     asset,
            sellChain:     'Solana',
            sellEurPayout: payout,
            kycReturnTo:   'sell-proc',
          }))
          // Simule vérification blockchain (2s) puis dispense
          setTimeout(() => go('sell-proc'), 2000)
          return
        }
      } catch(e) {}
    }
    setError('QR invalide — scannez le ticket RIFT (QR Code 2)')
    setScanned('')
  }

  return (
    <div className="scr on" id="s-sell-check" style={{ display:'flex', flexDirection:'column' }}>
      <div style={{ padding:'44px 18px 10px', flexShrink:0 }}>
        <div style={{ fontFamily:"'Poppins',sans-serif", fontSize:9, color:'var(--txt-dd)', letterSpacing:'0.1em', textTransform:'uppercase', marginBottom:4 }}>{tr(lang,'checkPending')}</div>
        <div style={{ fontFamily:"'Poppins',sans-serif", fontSize:18, fontWeight:700, color:'var(--txt)' }}>{tr(lang,'scanTicket')}</div>
        <div style={{ width:28, height:2, background:'var(--org)', borderRadius:1, marginTop:6 }}/>
      </div>
      <div style={{ flex:1, padding:'0 18px', display:'flex', flexDirection:'column', alignItems:'center', gap:14 }}>

        {/* Animation scanner */}
        <div style={{ background:'var(--surf)', border:`2px solid ${status?'var(--grn)':error?'var(--red)':'var(--pri-20)'}`, borderRadius:14, padding:24, display:'flex', flexDirection:'column', alignItems:'center', gap:10, width:'100%', position:'relative', overflow:'hidden' }}>
          <div style={{ position:'absolute', top:0, left:0, right:0, height:2, background:'var(--org)', animation:'scanBeam 2s linear infinite', opacity:.7 }}/>
          <div style={{ fontSize:48 }}>🎫</div>
          <div style={{ fontFamily:"'Poppins',sans-serif", fontSize:14, fontWeight:600, color:'var(--txt)', textAlign:'center' }}>
            {status || (error || tr(lang,'scanTicketInstr'))}
          </div>
          {status && <div style={{ color:'var(--grn)', fontSize:13 }}>{status}</div>}
          {error  && <div style={{ color:'var(--red)',  fontSize:12 }}>{error}</div>}
        </div>

        {/* Input HID caché */}
        <input
          ref={inputRef}
          autoFocus
          tabIndex={-1}
          value={scanned}
          onChange={e => handleScan(e.target.value)}
          onKeyDown={e => { if(e.key==='Enter' && scanned) processTicket() }}
          style={{ position:'fixed', opacity:0, width:0, height:0, top:0, left:0, pointerEvents:'none' }}
          autoComplete="off"
        />

        {/* Info */}
        <div className="info-box" style={{ width:'100%' }}>
          <div className="info-text">
            {tr(lang,'scanTicketInfo')}
          </div>
        </div>

        {/* Demo */}
        <button className="btn-ghost" style={{ width:'100%', opacity:.4, fontSize:11 }}
          onClick={() => { setScanned('rift://collect?ref=SELL-DEMO&payout=200&asset=SOL'); setTimeout(processTicket, 100) }}>
          ▶ Simuler scan ticket (Demo)
        </button>
      </div>
      <div className="nav-row">
        <button className="btn-ghost" onClick={() => go('action')}>{tr(lang,'back')}</button>
      </div>
    </div>
  )
}

// ─── SCREEN: SELL PROCESSING ──────────────────────────────────────────────────
function SellProcScreen({ go, session, addTx }) {
  const lang = session.lang || 'en'
  const sell_steps = getSellSteps(lang)
  const [steps, setSteps] = useState(sell_steps.map(() => 'idle'))
  const [offlineDetected, setOfflineDetected] = useState(false)
  const done = useRef(false)

  useEffect(() => {
    if (done.current) return
    done.current = true

    if (!navigator.onLine) {
      setOfflineDetected(true)
      setTimeout(() => go('sell-ticket'), 1800)
      return
    }

    let i = 0
    const run = () => {
      setSteps(prev => { const n=[...prev]; if(i>0)n[i-1]='done'; if(i<sell_steps.length)n[i]='active'; return n })
      i++
      if (i <= sell_steps.length) setTimeout(run, i === sell_steps.length ? 500 : 900)
      else {
        addTx({ time: new Date(), type:'SELL', asset: session.sellAsset||'SOL', chain: session.sellChain||'Solana', amt: session.sellEurPayout||100, comm: 5.0, kyc: session.kycLevel })
        setTimeout(() => go('collect'), 400)
      }
    }
    run()
  }, [])

  if (offlineDetected) {
    return (
      <div className="scr on" style={{ alignItems:'center', justifyContent:'center', background:'var(--bg)' }}>
        <div style={{ fontSize:48, marginBottom:16 }}>📡</div>
        <div style={{ fontFamily:"'Poppins',sans-serif", fontSize:18, fontWeight:700, marginBottom:6, color:'var(--org)' }}>{tr(lang,'machineOffline')}</div>
        <div style={{ fontFamily:"'Inter',sans-serif", fontSize:12, color:'var(--txt-d)', textAlign:'center', lineHeight:1.6, maxWidth:260, marginBottom:16 }}>
          {tr(lang,'offlineInfo')}
        </div>
        <div style={{ display:'flex', alignItems:'center', gap:8 }}>
          <div style={{ width:8, height:8, borderRadius:'50%', background:'var(--org)', animation:'pulse 1s infinite' }}/>
          <span style={{ fontFamily:"'Poppins',sans-serif", fontSize:11, color:'var(--txt-dd)' }}>{tr(lang,'printTicket')}…</span>
        </div>
      </div>
    )
  }

  return (
    <div className="scr on" style={{ alignItems: 'center', justifyContent: 'center', background: 'var(--bg)' }}>
      <div style={{ position: 'relative', width: 100, height: 100, marginBottom: 22, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        <div style={{ position: 'absolute', inset: 0, borderRadius: '50%', border: '1px solid rgba(74,222,128,.12)', animation: 'spin 4s linear infinite' }} />
        <div style={{ position: 'absolute', inset: 12, borderRadius: '50%', border: '1px solid rgba(74,222,128,.08)', animation: 'spin 3s linear infinite reverse' }} />
        <div style={{ width: 44, height: 44, borderRadius: 10, background: 'var(--grn)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 22 }}>💶</div>
      </div>
      <div style={{ fontFamily:"'Poppins',sans-serif", fontSize: 20, fontWeight: 700, marginBottom: 5 }}>{tr(lang,'confirmingSale')}</div>
      <div style={{ fontFamily:"'Inter',sans-serif", fontSize: 12, color: 'var(--txt-d)', marginBottom: 22 }}>{tr(lang,'pleaseWaitSell')}</div>
      <div style={{ width: 260 }}>
        {sell_steps.map((s, i) => (
          <div key={i} className="stage">
            <div className={`stage-dot ${steps[i]}`}>{steps[i]==='done'?'✓':steps[i]==='active'?'⟳':'○'}</div>
            <div className={`stage-txt ${steps[i]}`}>{s}</div>
          </div>
        ))}
      </div>
    </div>
  )
}

