// ─── ROOT COMPONENT ───────────────────────────────────────────────────────────
export default function RiftATM() {
  const [screen, setScreen]       = useState('idle')
  const [session, setSession]     = useState(initSession())
  const [txLog, setTxLog]         = useState([])
  const [pending, setPending]     = useState([])
  const [showTO, setShowTO]       = useState(false)
  const [toSecs, setToSecs]       = useState(30)
  const [showSettings, setShowSettings] = useState(false)
  const [lang, setLang]           = useState('en')
  const toTimer  = useRef(null)
  const toCount  = useRef(null)
  const screenRef = useRef('idle')
  const sessionRef = useRef(initSession())

  // Screens where timeout overlay must NEVER appear
  const noTimeoutScreens = new Set(['idle', 'proc', 'sell-proc', 'success', 'sell-success', 'collect', 'sell-ticket'])

  const resetTimeout = useCallback(() => {
    clearTimeout(toTimer.current)
    clearInterval(toCount.current)
    setShowTO(false)
    setToSecs(30)
  }, [])

  const startTimeout = useCallback(() => {
    resetTimeout()
    toTimer.current = setTimeout(() => {
      // Never show if cash inserted or in a transaction screen
      const s = screenRef.current
      const sess = sessionRef.current
      const hasCash = (sess.cashAmt > 0 || sess.cardAmt > 0)
      if (noTimeoutScreens.has(s) || hasCash) return
      setToSecs(30)
      setShowTO(true)
      // Countdown — if reaches 0 and still showing, go home
      let secs = 30
      toCount.current = setInterval(() => {
        secs--
        setToSecs(secs)
        if (secs <= 0) {
          clearInterval(toCount.current)
          setShowTO(false)
          setScreen('idle')
          setSession(initSession())
        }
      }, 1000)
    }, 60000)
  }, [resetTimeout])

  const go = useCallback((s) => {
    setScreen(s)
    screenRef.current = s
    resetTimeout()
    if (!noTimeoutScreens.has(s)) startTimeout()
  }, [resetTimeout, startTimeout])

  const updateSession = useCallback((updater) => {
    setSession(prev => {
      const next = typeof updater === 'function' ? updater(prev) : updater
      sessionRef.current = next
      return next
    })
  }, [])

  const addTx = useCallback((tx) => setTxLog(log => [tx, ...log]), [])

  const continueSession = useCallback(() => {
    resetTimeout()
    startTimeout()
  }, [resetTimeout, startTimeout])

  useEffect(() => () => { clearTimeout(toTimer.current); clearInterval(toCount.current) }, [])

  useEffect(() => {
    const style = document.createElement('style')
    style.id = 'rift-styles'
    style.textContent = CSS
    document.head.appendChild(style)
    return () => document.getElementById('rift-styles')?.remove()
  }, [])

  const screenProps = { go, session, setSession: updateSession, addTx, pending, setPending }

  return (
    <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'center', background: '#000', minHeight: '100vh', gap: 0 }}>
      <div className="atm-root">
        <StatusBar screen={screen} kycLevel={session.kycLevel} onSettings={() => setShowSettings(true)} lang={lang} />
        <SettingsOverlay open={showSettings} onClose={() => setShowSettings(false)} lang={lang} setLang={(l) => { setLang(l); updateSession(s => ({...s, lang: l})) }} />

        {/* Timeout overlay — shows after 60s inactivity, counts down 30s then goes home */}
        <div id="toOv" className={showTO ? 'on' : ''}>
          <div className="to-ring">{toSecs}</div>
          <div style={{ fontFamily:"'Poppins',sans-serif", fontSize: 18, fontWeight: 700, marginBottom: 8 }}>Still there?</div>
          <div style={{ fontFamily:"'Inter',sans-serif", fontSize: 12, color: 'var(--txt-d)', marginBottom: 22 }}>
            Returning to home in {toSecs}s
          </div>
          <button className="btn-g" style={{ width: 220 }} onClick={continueSession}>CONTINUE SESSION</button>
        </div>

        {screen === 'idle'        && <IdleScreen {...screenProps} />}
        {screen === 'action'      && <ActionScreen {...screenProps} session={session} />}
        {screen === 'amount'      && <AmountScreen {...screenProps} />}
        {screen === 'kyc'         && <KycScreen {...screenProps} />}
        {screen === 'kyc-scan'    && <KycScanScreen {...screenProps} />}
        {screen === 'kyc-manual'  && <KycManualScreen {...screenProps} />}
        {screen === 'kyc-selfie'  && <KycSelfieScreen {...screenProps} />}
        {screen === 'kyc-id'      && <KycIdScreen {...screenProps} />}
        {screen === 'asset'       && <AssetScreen {...screenProps} />}
        {screen === 'wallet'      && <WalletScreen {...screenProps} />}
        {screen === 'wallet-scan' && <WalletScanScreen {...screenProps} />}
        {screen === 'proc'        && <ProcScreen {...screenProps} key={Date.now()} />}
        {screen === 'success'     && <SuccessScreen {...screenProps} />}
        {screen === 'sell-send'   && <SellSendScreen {...screenProps} />}
        {screen === 'sell-wait'   && <SellWaitScreen {...screenProps} />}
        {screen === 'sell-check'  && <SellCheckScreen {...screenProps} />}
        {screen === 'sell-proc'   && <SellProcScreen {...screenProps} key={Date.now()} />}
        {screen === 'collect'     && <CollectScreen {...screenProps} />}
        {screen === 'sell-success'&& <SellSuccessScreen {...screenProps} />}
        {screen === 'sell-ticket' && <SellTicketScreen {...screenProps} />}
        {screen === 'info'        && <InfoScreen {...screenProps} />}
      </div>
      <AdminPanel txLog={txLog} pending={pending} />
    </div>
  )
}
